const trigger = $('Slack: reakce :cowork: (Socket Mode)').first().json;
const messages = $('Slack: Get thread').all().map(i => i.json);
const channel = $('Slack: Channel info').first().json;

const channelName = channel.name || 'unknown';
const rootMsg = messages[0] || {};
const rootText = (rootMsg.text || '').substring(0, 60).replace(/[^a-z0-9 ]/gi,'').trim().replace(/\s+/g,'-').toLowerCase();

const date = new Date((parseFloat(rootMsg.ts || (Date.now()/1000)))*1000);
const ts = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}-${String(date.getHours()).padStart(2,'0')}${String(date.getMinutes()).padStart(2,'0')}`;
const filename = `${ts}-${channelName}-${rootText || 'msg'}.md`.substring(0, 120);

const messageLink = `https://slack.com/archives/${trigger.item.channel}/p${(rootMsg.ts || '').replace('.','')}`;

const md = [
  `# #${channelName} — ${date.toLocaleDateString('cs-CZ')} ${date.toLocaleTimeString('cs-CZ', {hour:'2-digit',minute:'2-digit'})}`,
  '',
  `**Odkaz:** ${messageLink}`,
  `**Reakce :cowork: od:** ${trigger.user || '?'}`,
  `**Zpráv ve vlákně:** ${messages.length}`,
  '',
  '## Zprávy',
  '',
  ...messages.map(m => {
    const mDate = new Date(parseFloat(m.ts || 0)*1000).toLocaleString('cs-CZ');
    return `### ${m.user || m.username || '?'} — ${mDate}\n\n${m.text || ''}\n`;
  }),
  ''
].join('\n');

return [{ json: { filename, content: md } }];
